            const deltaX = moveEvent.clientX - startX;
            const newWidthPx = startWidth + deltaX;
            const newWidthPercent = Math.min(100, Math.max(20, (newWidthPx / parentWidth) * 100));
            onUpdateStyle(item.id, { widthPercent: Math.round(newWidthPercent) });
        };

        const onMouseUp = () => {
            window.removeEventListener('mousemove', onMouseMove);
            window.removeEventListener('mouseup', onMouseUp);
        };

        window.addEventListener('mousemove', onMouseMove);
        window.addEventListener('mouseup', onMouseUp);
    };

    return (
        <div 
            ref={blockRef}
            onClick={(e) => { if(designMode) { e.stopPropagation(); onSelect(); } }}
            className={`relative flex flex-col transition-all duration-200 group/block 
                ${designMode ? 'cursor-pointer hover:bg-indigo-50/10' : ''} 
                ${isSelected && designMode ? 'ring-2 ring-indigo-500 bg-white shadow-lg z-10' : designMode ? 'hover:ring-1 hover:ring-indigo-300' : ''}`}
            style={{ 
                width: `${item.style.widthPercent}%`,
                minHeight: `${item.style.minHeight}px`,
                padding: `${item.style.padding}px`,
                marginTop: `${item.style.marginTop}px`,
                marginBottom: `${item.style.marginBottom}px`,
                alignSelf: item.style.alignSelf,
                backgroundColor: item.style.backgroundColor || 'transparent',
                border: item.style.borderWidth ? `${item.style.borderWidth}px solid #e4e4e7` : designMode ? '1px dashed transparent' : 'none',
                borderRadius: '12px'
            }}
        >
            {designMode && (
                <BlockControls 
                    onDelete={onDelete} 
                    onMoveUp={() => onMove('up')} 
                    onMoveDown={() => onMove('down')}
                    onAlign={(a) => onUpdateStyle(item.id, { alignSelf: a })}
                />
            )}

            {children}

            {designMode && isSelected && (
                <ResizeHandle onResize={handleResize} />
            )}
        </div>
    );
};

